import{a as e,c as t,i as n,l as r,n as i,o as a,r as o,s,t as c}from"./app-BDbP51_p.js";var l=JSON.parse(`{"path":"/redaction-processing/width_calculator_documentation.html","title":"width_calculator.py","lang":"en-US","frontmatter":{},"git":{"updatedTime":1774704928000,"contributors":[{"name":"JaguarM","username":"JaguarM","email":"39597011+JaguarM@users.noreply.github.com","commits":3,"url":"https://github.com/JaguarM"}],"changelog":[{"hash":"3bbb491f17913ec6288159d2b53d03c92c805a63","time":1774704928000,"email":"39597011+JaguarM@users.noreply.github.com","author":"JaguarM","message":"Made that shit modular with django apps"},{"hash":"ead06576b31ffd1a26400fd90bfc269f882305f3","time":1774476550000,"email":"39597011+JaguarM@users.noreply.github.com","author":"JaguarM","message":"Detect scale/size and update PDF analysis output"},{"hash":"f7330e85197db34564e6215e1d272b22e506e24e","time":1774437245000,"email":"39597011+JaguarM@users.noreply.github.com","author":"JaguarM","message":"Add redaction detection backend and docs"}]},"filePathRelative":"redaction-processing/width_calculator_documentation.md"}`),u={name:`width_calculator_documentation.md`};function d(c,l,u,d,f,p){let m=t(`RouteLink`);return s(),o(`div`,null,[l[5]||=n(`<h1 id="width-calculator-py" tabindex="-1"><a class="header-anchor" href="#width-calculator-py"><span>width_calculator.py</span></a></h1><p><a href="../../text_tool/logic/width_calculator.py">width_calculator.py</a> provides precision text-width measurement for candidate name matching.</p><hr><h2 id="functions" tabindex="-1"><a class="header-anchor" href="#functions"><span>Functions</span></a></h2><h3 id="get-text-widths-texts-font-name-font-size-force-uppercase-scale-factor-kerning-ligatures" tabindex="-1"><a class="header-anchor" href="#get-text-widths-texts-font-name-font-size-force-uppercase-scale-factor-kerning-ligatures"><span><code>get_text_widths(texts, font_name, font_size, force_uppercase, scale_factor, kerning, ligatures)</code></span></a></h3><p>Calculates pixel widths for a list of text strings.</p><p><strong>Parameters:</strong></p><table><thead><tr><th>Parameter</th><th>Type</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>texts</code></td><td>list[str]</td><td>—</td><td>Strings to measure</td></tr><tr><td><code>font_name</code></td><td>str</td><td><code>&quot;times.ttf&quot;</code></td><td>Font filename</td></tr><tr><td><code>font_size</code></td><td>int/float</td><td><code>12</code></td><td>Font size in <strong>points</strong></td></tr><tr><td><code>force_uppercase</code></td><td>bool</td><td><code>False</code></td><td>Convert text to uppercase before measuring</td></tr><tr><td><code>scale_factor</code></td><td>float</td><td><code>1.35</code></td><td>Multiplier applied to the raw advance width</td></tr><tr><td><code>kerning</code></td><td>bool</td><td><code>True</code></td><td>Enable OpenType <code>kern</code> feature</td></tr><tr><td><code>ligatures</code></td><td>bool</td><td><code>True</code></td><td>Enable <code>liga</code> and <code>clig</code> features</td></tr></tbody></table><p><strong>Output:</strong></p><div class="language-python line-numbers-mode" data-highlighter="prismjs" data-ext="py"><pre><code class="language-python"><span class="line"><span class="token punctuation">[</span><span class="token punctuation">{</span><span class="token string">&quot;text&quot;</span><span class="token punctuation">:</span> <span class="token string">&quot;Jeffrey Epstein&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;width&quot;</span><span class="token punctuation">:</span> <span class="token number">89.472</span><span class="token punctuation">}</span><span class="token punctuation">,</span> <span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">]</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><hr><h3 id="font-resolution" tabindex="-1"><a class="header-anchor" href="#font-resolution"><span>Font Resolution</span></a></h3><p>The font is searched in this order:</p><ol><li>Direct path (<code>font_name</code> as-is)</li><li><code>assets/fonts/{font_name}</code></li><li><code>assets/fonts/{font_name}.ttf</code></li></ol><p>System font directories are intentionally excluded to ensure consistent results across environments.</p><hr><h3 id="harfbuzz-engine-primary" tabindex="-1"><a class="header-anchor" href="#harfbuzz-engine-primary"><span>HarfBuzz Engine (Primary)</span></a></h3><p>When <code>uharfbuzz</code> is available:</p><div class="language-python line-numbers-mode" data-highlighter="prismjs" data-ext="py"><pre><code class="language-python"><span class="line">face <span class="token operator">=</span> hb<span class="token punctuation">.</span>Face<span class="token punctuation">(</span>font_data<span class="token punctuation">)</span></span>
<span class="line">font <span class="token operator">=</span> hb<span class="token punctuation">.</span>Font<span class="token punctuation">(</span>face<span class="token punctuation">)</span></span>
<span class="line">upem <span class="token operator">=</span> face<span class="token punctuation">.</span>upem   <span class="token comment"># units per em</span></span>
<span class="line"></span>
<span class="line">buf <span class="token operator">=</span> hb<span class="token punctuation">.</span>Buffer<span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line">buf<span class="token punctuation">.</span>add_str<span class="token punctuation">(</span>text<span class="token punctuation">)</span></span>
<span class="line">buf<span class="token punctuation">.</span>guess_segment_properties<span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line">hb<span class="token punctuation">.</span>shape<span class="token punctuation">(</span>font<span class="token punctuation">,</span> buf<span class="token punctuation">,</span> features<span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line">total_advance <span class="token operator">=</span> <span class="token builtin">sum</span><span class="token punctuation">(</span>pos<span class="token punctuation">.</span>x_advance <span class="token keyword">for</span> pos <span class="token keyword">in</span> buf<span class="token punctuation">.</span>glyph_positions<span class="token punctuation">)</span></span>
<span class="line">pixel_width <span class="token operator">=</span> <span class="token punctuation">(</span>total_advance <span class="token operator">/</span> upem<span class="token punctuation">)</span> <span class="token operator">*</span> font_size <span class="token operator">*</span> scale_factor</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>Features controlled:</strong></p><table><thead><tr><th>Feature</th><th>Enabled</th><th>Disabled</th></tr></thead><tbody><tr><td><code>kern</code></td><td>Default</td><td><code>kerning=False</code></td></tr><tr><td><code>liga</code></td><td>Default</td><td><code>ligatures=False</code></td></tr><tr><td><code>clig</code></td><td>Default</td><td><code>ligatures=False</code></td></tr><tr><td><code>dlig</code></td><td>Never</td><td><code>ligatures=False</code></td></tr></tbody></table><h3 id="pillow-fallback" tabindex="-1"><a class="header-anchor" href="#pillow-fallback"><span>Pillow Fallback</span></a></h3><p>If HarfBuzz fails or is not installed, falls back to <code>ImageFont.truetype()</code> with <code>font.getlength()</code>. This method does not support fine-grained kerning/ligature control.</p><hr><h3 id="get-available-fonts" tabindex="-1"><a class="header-anchor" href="#get-available-fonts"><span><code>get_available_fonts()</code></span></a></h3><p>Scans the <code>assets/fonts/</code> directory and returns a list of <code>.ttf</code> filenames.</p><p><strong>Output:</strong> <code>[&quot;times.ttf&quot;, &quot;arial.ttf&quot;, ...]</code></p><p>Used by the <code>/fonts-list</code> API endpoint to populate the frontend font dropdown.</p><hr><h2 id="scale-factor" tabindex="-1"><a class="header-anchor" href="#scale-factor"><span>Scale Factor</span></a></h2><p><code>scale_factor</code> is the multiplier that converts a raw typographic advance (in font points) into the <strong>image pixel width</strong> used by the redaction overlay coordinates.</p><h3 id="formula" tabindex="-1"><a class="header-anchor" href="#formula"><span>Formula</span></a></h3><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code class="language-text"><span class="line">pixel_width = (advance / upem) × font_size_pt × scale_factor</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>For the width to match a redaction box measured in the 816 × 1056 px embedded page images:</p><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code class="language-text"><span class="line">scale_factor = img_width_px / page_width_pt</span>
<span class="line">             = 816 / 612</span>
<span class="line">             = 4/3</span>
<span class="line">             ≈ 1.3333</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>This is equivalent to converting from 72 dpi (PDF points) to 96 dpi (screen pixels): <code>96 / 72 = 4/3</code>.</p><h3 id="how-the-frontend-sets-scale-factor" tabindex="-1"><a class="header-anchor" href="#how-the-frontend-sets-scale-factor"><span>How the frontend sets scale_factor</span></a></h3><p>The <code>/analyze-pdf</code> response includes <code>suggested_scale</code> (an integer percentage). <code>views.py</code> divides it by 100 before passing it to <code>get_text_widths()</code>:</p><div class="language-python line-numbers-mode" data-highlighter="prismjs" data-ext="py"><pre><code class="language-python"><span class="line">scale_factor <span class="token operator">=</span> scale <span class="token operator">/</span> <span class="token number">100.0</span>   <span class="token comment"># e.g. 133 / 100 = 1.33</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>The auto-detected value <code>suggested_scale = 133</code> corresponds to <code>scale_factor ≈ 1.333</code>, which correctly maps 12 pt Times New Roman to its pixel width in the embedded page images.</p><blockquote><p><strong>Note:</strong> The function signature&#39;s default <code>scale_factor=1.35</code> is a legacy approximation of 4/3. In normal operation the frontend always supplies an explicit scale from the <code>suggested_scale</code> auto-detection, so the default is rarely used.</p></blockquote>`,41),i(`p`,null,[l[1]||=e(`For a full derivation of the correct scale value and why the old formula (`,-1),l[2]||=i(`code`,null,`(median_size / 12) × (816/612)² × 100 ≈ 178`,-1),l[3]||=e(`) was incorrect, see `,-1),a(m,{to:`/redaction-processing/scale-and-size-detection.html`},{default:r(()=>[...l[0]||=[e(`Scale & Size Detection`,-1)]]),_:1}),l[4]||=e(`.`,-1)])])}var f=c(u,[[`render`,d]]);export{l as _pageData,f as default};